package com.google.gson.interceptors;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;

class InterceptorFactoryTest {

  @Retention(RetentionPolicy.RUNTIME)
  @interface Intercept {
    // dummy annotation for test
  }

  static class AnnotatedClass {}

  static class NonAnnotatedClass {}

  @Mock
  private Gson gson;

  @Mock
  private TypeAdapter<Object> delegateAdapter;

  private InterceptorFactory interceptorFactory;

  @BeforeEach
  void setup() {
    MockitoAnnotations.openMocks(this);
    interceptorFactory = new InterceptorFactory();
  }

  @Test
  void create_shouldReturnNullIfNoInterceptAnnotation() {
    TypeToken<NonAnnotatedClass> typeToken = TypeToken.get(NonAnnotatedClass.class);
    TypeAdapter<?> adapter = interceptorFactory.create(gson, typeToken);
    assertNull(adapter);
  }

  @Test
  void create_shouldReturnInterceptorAdapterIfInterceptAnnotationPresent() {
    // Create a subclass of AnnotatedClass with @Intercept annotation
    @Intercept
    class Annotated {}

    TypeToken<Annotated> typeToken = TypeToken.get(Annotated.class);

    when(gson.getDelegateAdapter(interceptorFactory, typeToken)).thenReturn(delegateAdapter);

    @SuppressWarnings("unchecked")
    TypeAdapter<Annotated> adapter = interceptorFactory.create(gson, typeToken);

    assertNotNull(adapter);
    // The returned adapter should be an instance of InterceptorAdapter
    assertEquals("com.google.gson.interceptors.InterceptorAdapter", adapter.getClass().getName());

    // Verify delegate adapter was requested
    verify(gson).getDelegateAdapter(interceptorFactory, typeToken);
  }
}
